const item = $input.first().json || {};
const body = item.body || item;
const expectedPassword = 'gundam';
const password = String(body.password || '').trim();
const range = String(body.range || '30').trim();

const days = Number(range);
let cutoffISO = '2000-01-01T00:00:00.000Z';
if (Number.isFinite(days)) {
  cutoffISO = new Date(Date.now() - days * 24 * 60 * 60 * 1000).toISOString();
}

return [{
  json: {
    ok: password && password === expectedPassword,
    range,
    cutoffISO,
    response: { ok: false, message: '管理密碼錯誤或沒有權限' }
  }
}];

const auth = $('驗證管理密碼').first().json || {};
const range = auth.range || '30';
const batches = $('讀取掃描批次').all().map((item) => item.json || {});
const details = $input.all().map((item) => item.json || {});
const people = (() => { try { return $('讀取人員清單').all().map((i) => i.json || {}); } catch (e) { return []; } })();

function propVal(row, name) {
  const p = row?.properties?.[name];
  if (p) {
    switch (p.type) {
      case 'title': return (p.title || []).map((t) => t.plain_text).join('');
      case 'rich_text': return (p.rich_text || []).map((t) => t.plain_text).join('');
      case 'select': return p.select?.name || '';
      case 'status': return p.status?.name || '';
      case 'multi_select': return (p.multi_select || []).map((o) => o.name);
      case 'number': return p.number ?? '';
      case 'checkbox': return p.checkbox === true;
      case 'date': return p.date?.start || '';
      default: return '';
    }
  }
  if (row?.[name] !== undefined && row?.[name] !== null) return row[name];
  if (row?.['property_' + name] !== undefined && row?.['property_' + name] !== null) return row['property_' + name];
  return '';
}

function num(value) {
  const n = Number(String(value ?? '').replace(/,/g, '').trim());
  return Number.isFinite(n) ? n : 0;
}
function truthy(value) {
  return value === true || value === '__YES__' || value === 'true' || value === 1;
}
function parseTime(value) {
  const raw = String(value || '').trim();
  if (!raw) return null;
  const t = new Date(raw);
  return Number.isNaN(t.getTime()) ? null : t;
}
function dayKey(t) {
  if (!t) return '';
  const y = t.getFullYear();
  const m = String(t.getMonth() + 1).padStart(2, '0');
  const d = String(t.getDate()).padStart(2, '0');
  return `${y}-${m}-${d}`;
}
function sameDay(date) {
  if (!date) return false;
  const now = new Date();
  return date.getFullYear() === now.getFullYear() && date.getMonth() === now.getMonth() && date.getDate() === now.getDate();
}
function batchTime(b) {
  return propVal(b, '上傳時間') || b.created_time || b.createdTime || propVal(b, '完成時間') || '';
}
function inRange(timeStr) {
  if (range === 'all') return true;
  const days = Number(range);
  if (!Number.isFinite(days)) return true;
  const t = parseTime(timeStr);
  if (!t) return true;
  return t >= new Date(Date.now() - days * 24 * 60 * 60 * 1000);
}

const nickById = new Map();
const nickByName = new Map();
for (const p of people) {
  const uid = String(propVal(p, 'LINE userId')).trim();
  const nm = String(propVal(p, '名稱')).trim();
  const nk = String(propVal(p, '暱稱')).trim();
  if (!nk) continue;
  if (uid) nickById.set(uid, nk);
  if (nm) nickByName.set(nm, nk);
}
function nickOf(userId, name) {
  return nickById.get(String(userId || '').trim()) || nickByName.get(String(name || '').trim()) || '';
}

function errorTypesOf(row) {
  const raw = propVal(row, '錯誤類型');
  let types = [];
  if (Array.isArray(raw)) types = raw.map((x) => String(x?.name || x).trim()).filter(Boolean);
  else if (typeof raw === 'string' && raw.trim()) types = raw.split(/[,，、]/).map((s) => s.trim()).filter(Boolean);
  if (types.length) return types;
  const reason = String(propVal(row, '異常原因') || propVal(row, '備註') || '');
  const known = ['製令單號未判讀', '品號未判讀', '品號開頭非英文', '主檔查無品號', '規格未判讀', '規格不符', '字跡模糊'];
  return known.filter((k) => reason.includes(k));
}

// ---- 彙總數字全部由掃描批次計算（少量、完整、可靠）----
const scopedBatches = batches.filter((b) => inRange(batchTime(b)));

let totalItems = 0, passedItems = 0, abnormalItems = 0, correctedItems = 0;
let procSum = 0, procCount = 0, failedBatches = 0, todayBatches = 0;
const operatorMap = new Map();
const dailyMap = new Map();
const notifyMap = new Map();
const recent = [];

for (const b of scopedBatches) {
  const total = num(propVal(b, '總筆數'));
  const passed = num(propVal(b, '通過筆數'));
  const abnormal = num(propVal(b, '異常筆數'));
  const corrected = num(propVal(b, '人工修正筆數'));
  totalItems += total; passedItems += passed; abnormalItems += abnormal; correctedItems += corrected;
  const proc = num(propVal(b, '處理秒數'));
  if (proc > 0) { procSum += proc; procCount += 1; }
  if (String(propVal(b, '狀態')) === '失敗') failedBatches += 1;
  const t = parseTime(batchTime(b));
  if (sameDay(t)) todayBatches += 1;

  const uid = String(propVal(b, 'LINE userId')).trim();
  const name = String(propVal(b, '操作人') || uid || '未命名').trim();
  const key = uid || name;
  if (!operatorMap.has(key)) operatorMap.set(key, { name, userId: uid, total: 0, passed: 0, abnormal: 0, corrected: 0 });
  const op = operatorMap.get(key);
  op.total += total; op.passed += passed; op.abnormal += abnormal; op.corrected += corrected;

  const day = dayKey(t);
  if (day) {
    if (!dailyMap.has(day)) dailyMap.set(day, { date: day, batches: 0, total: 0, passed: 0, abnormal: 0 });
    const d = dailyMap.get(day);
    d.batches += 1; d.total += total; d.passed += passed; d.abnormal += abnormal;
  }

  const ns = String(propVal(b, '通知狀態') || '未記錄').trim() || '未記錄';
  notifyMap.set(ns, (notifyMap.get(ns) || 0) + 1);

  recent.push({
    time: batchTime(b),
    batchId: propVal(b, '批次ID') || propVal(b, '名稱'),
    operator: propVal(b, '操作人'),
    operatorNick: nickOf(uid, propVal(b, '操作人')),
    orderNo: propVal(b, '製令單號'),
    status: propVal(b, '狀態'),
    notifyStatus: propVal(b, '通知狀態'),
    processingSeconds: proc,
    total, passed, abnormal,
    accuracy: total ? passed / total : 0
  });
}

const operators = [...operatorMap.values()].map((o) => ({
  ...o,
  accuracy: o.total ? o.passed / o.total : 0,
  correctionRate: o.total ? o.corrected / o.total : 0,
  nickname: nickOf(o.userId, o.name)
})).sort((a, b) => b.total - a.total);

const daily = [...dailyMap.values()].map((d) => ({ ...d, accuracy: d.total ? d.passed / d.total : 0 })).sort((a, b) => a.date.localeCompare(b.date));
recent.sort((a, b) => String(b.time).localeCompare(String(a.time)));
const notify = [...notifyMap.entries()].map(([name, count]) => ({ name, count }));

// ---- 分布類由明細樣本（上限 500 筆）計算 ----
const sampleDetails = details;
const abnormalDetails = sampleDetails.filter((r) => propVal(r, '比對結果') === '異常');

const errorMap = new Map();
for (const r of abnormalDetails) for (const tp of errorTypesOf(r)) errorMap.set(tp, (errorMap.get(tp) || 0) + 1);
const errorTypes = [...errorMap.entries()].map(([name, count]) => ({ name, count })).sort((a, b) => b.count - a.count);

const ocrStatusMap = new Map();
for (const r of sampleDetails) {
  const s = String(propVal(r, 'OCR狀態') || '未標記').trim() || '未標記';
  ocrStatusMap.set(s, (ocrStatusMap.get(s) || 0) + 1);
}
const ocrStatus = [...ocrStatusMap.entries()].map(([name, count]) => ({ name, count }));

const partMap = new Map();
for (const r of abnormalDetails) {
  const part = String(propVal(r, '品號') || propVal(r, '原始品號') || '').trim() || '（空品號）';
  if (!partMap.has(part)) partMap.set(part, { partNo: part, count: 0, reasons: new Set() });
  const it = partMap.get(part);
  it.count += 1;
  for (const tp of errorTypesOf(r)) it.reasons.add(tp);
}
const problemParts = [...partMap.values()].map((p) => ({ partNo: p.partNo, count: p.count, reasons: [...p.reasons] })).sort((a, b) => b.count - a.count).slice(0, 10);

const completeItems = sampleDetails.filter((r) => String(propVal(r, 'OCR狀態')) === '辨識完成').length;
const detailSample = sampleDetails.length;

const detailRows = sampleDetails.slice(0, 500).map((r) => ({
  batchId: String(propVal(r, '批次ID') || ''),
  partNo: String(propVal(r, '品號') || propVal(r, '原始品號') || ''),
  spec: String(propVal(r, '規格') || ''),
  status: String(propVal(r, '比對結果') || ''),
  ocrStatus: String(propVal(r, 'OCR狀態') || ''),
  corrected: truthy(propVal(r, '是否人工修正')),
  errorTypes: errorTypesOf(r),
  note: String(propVal(r, '異常原因') || propVal(r, '備註') || '')
}));

const avgProcessing = procCount ? procSum / procCount : 0;

return [{
  json: {
    ok: true,
    summary: {
      accuracy_rate: totalItems ? passedItems / totalItems : 0,
      total_items: totalItems,
      passed_items: passedItems,
      abnormal_items: abnormalItems,
      total_batches: scopedBatches.length,
      today_batches: todayBatches,
      failed_batches: failedBatches,
      corrected_items: correctedItems,
      correction_rate: totalItems ? correctedItems / totalItems : 0,
      ocr_complete_rate: detailSample ? completeItems / detailSample : 0,
      avg_processing_seconds: Math.round(avgProcessing * 10) / 10,
      detail_sample: detailSample
    },
    operators,
    recent,
    daily,
    errorTypes,
    ocrStatus,
    problemParts,
    notify,
    details: detailRows
  }
}];
